import{_ as e,o as a,c as o,a4 as r}from"./chunks/framework.4M7SpZrd.js";const p=JSON.parse('{"title":"Monitoramento & Alertas — Regras de Negocio","description":"","frontmatter":{},"headers":[],"relativePath":"api/monitoring-alerts.md","filePath":"api/monitoring-alerts.md"}'),d={name:"api/monitoring-alerts.md"};function i(n,t,l,c,s,m){return a(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="monitoramento-alertas-—-regras-de-negocio" tabindex="-1">Monitoramento &amp; Alertas — Regras de Negocio <a class="header-anchor" href="#monitoramento-alertas-—-regras-de-negocio" aria-label="Permalink to &quot;Monitoramento &amp; Alertas — Regras de Negocio&quot;">​</a></h1><blockquote><p><strong>Endpoints completos:</strong> <a href="http://kubex.test/api/docs#/monitoring" target="_blank" rel="noreferrer">Swagger UI — Monitoring</a> | <a href="http://kubex.test/api/docs#/alerts" target="_blank" rel="noreferrer">Alerts</a></p></blockquote><h2 id="monitoring-hub-get-monitoring-status" tabindex="-1">Monitoring Hub (<code>GET /monitoring/status</code>) <a class="header-anchor" href="#monitoring-hub-get-monitoring-status" aria-label="Permalink to &quot;Monitoring Hub (`GET /monitoring/status`)&quot;">​</a></h2><p>Endpoint enriquecido que retorna tudo que o hub precisa em uma unica chamada: status, motores, onboarding, alertas recentes.</p><h3 id="intervalos-de-scan" tabindex="-1">Intervalos de Scan <a class="header-anchor" href="#intervalos-de-scan" aria-label="Permalink to &quot;Intervalos de Scan&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Plano</th><th>Intervalo</th><th>Motors habilitados</th></tr></thead><tbody><tr><td>Gratuito</td><td>Sem monitoramento</td><td>1, 2, 4, 5</td></tr><tr><td>Essencial</td><td>24h</td><td>1, 2, 4, 5, 9, 10, 14</td></tr><tr><td>Pro</td><td>6h</td><td>1, 2, 4, 5, 9, 10, 11, 13, 14, 15, 16, 17</td></tr><tr><td>Fundador</td><td>12h</td><td>1, 2, 4, 5, 9, 10, 11, 13, 14, 15, 16, 17</td></tr></tbody></table><h2 id="upload-para-monitoramento-post-monitoring-images" tabindex="-1">Upload para Monitoramento (<code>POST /monitoring/images</code>) <a class="header-anchor" href="#upload-para-monitoramento-post-monitoring-images" aria-label="Permalink to &quot;Upload para Monitoramento (`POST /monitoring/images`)&quot;">​</a></h2><p>Registra imagem para monitoramento continuo <strong>sem disparar busca reversa</strong>. Entra automaticamente no ciclo de re-scan do Celery Beat (<code>trigger_image_rescan</code>).</p><h2 id="tipos-de-alerta" tabindex="-1">Tipos de Alerta <a class="header-anchor" href="#tipos-de-alerta" aria-label="Permalink to &quot;Tipos de Alerta&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Tipo</th><th>Descricao</th><th>Motor(es)</th></tr></thead><tbody><tr><td><code>image_match</code></td><td>Match por pHash</td><td>1, 2</td></tr><tr><td><code>face_match</code></td><td>Match facial</td><td>6</td></tr><tr><td><code>name_match</code></td><td>Match por nome/marca</td><td>4</td></tr><tr><td><code>telegram_match</code></td><td>Match no Telegram</td><td>5</td></tr><tr><td><code>social_match</code></td><td>Match em rede social</td><td>9, 13, 14, 15, 16, 18, FB, FL</td></tr></tbody></table><h2 id="deduplicacao-de-alertas" tabindex="-1">Deduplicacao de Alertas <a class="header-anchor" href="#deduplicacao-de-alertas" aria-label="Permalink to &quot;Deduplicacao de Alertas&quot;">​</a></h2><ul><li>Campo <code>found_url_hash</code> (hash da URL encontrada)</li><li>Constraint unica: <code>user_id</code> + <code>found_url_hash</code> + <code>alert_type</code></li><li>UPSERT: se duplicata, atualiza <code>last_seen</code> e <code>times_found</code></li></ul><h2 id="monitoramento-por-nome-monitoredname" tabindex="-1">Monitoramento por Nome (<code>MonitoredName</code>) <a class="header-anchor" href="#monitoramento-por-nome-monitoredname" aria-label="Permalink to &quot;Monitoramento por Nome (`MonitoredName`)&quot;">​</a></h2><p>Modelo para monitoramento de nomes/marcas. Limites por plano controlados via <code>max_monitored_names</code> na tabela <code>plans</code>:</p><table tabindex="0"><thead><tr><th>Plano</th><th>Max nomes monitorados</th></tr></thead><tbody><tr><td>Gratuito</td><td>0</td></tr><tr><td>Essencial</td><td>5</td></tr><tr><td>Fundador</td><td>20</td></tr><tr><td>Pro</td><td>50</td></tr><tr><td>Premium</td><td>999</td></tr></tbody></table><h2 id="evidence-thumbnail-lgpd" tabindex="-1">Evidence Thumbnail (LGPD) <a class="header-anchor" href="#evidence-thumbnail-lgpd" aria-label="Permalink to &quot;Evidence Thumbnail (LGPD)&quot;">​</a></h2><ul><li>JPEG 200px capturado via httpx (SSRF guard aplicado)</li><li>Base64 em <code>evidence_thumbnail</code></li><li>Expira em 90 dias (<code>evidence_expires_at</code>)</li><li>Celery Beat: <code>cleanup_expired_evidence</code> diariamente</li></ul>',17)])])}const u=e(d,[["render",i]]);export{p as __pageData,u as default};
